router.post('/vulnerable/apply-coupon', (req, res) => {
  const { orderId, code } = req.body;
  const coupon = db.prepare(
    'SELECT * FROM coupons WHERE code = ?'
  ).get(code);
  if (!coupon) return res.status(404).json({ error: 'Invalid coupon' });

  // ⚠ No check on max_uses or duplicate application
  db.prepare(
    'UPDATE orders SET discount = discount + ? WHERE id = ?'
  ).run(coupon.discount_percent, orderId);

  res.json({ applied: coupon.discount_percent });
});

